{"query":"
    mutation addItems(
      $items: [String!]!
      $assetID: ID!
      $assetType: String = "class"
    ) {
      shoppingList {
        addItems(
          items: $items
          asset: { id: $assetID, brand: "food", type: $assetType }
        ) {
          items {
            text
            measure
          }
        }
      }
    }
  ","variables":{"items":["1/4 cup butter, softened","1/2 cup dark brown sugar","1/4 cup granulated sugar","1/4 cup canola oil","1 egg","1 teaspoon vanilla extract","1/2 cup all-purpose flour","1/2 cup whole-wheat pastry flour","1/4 cup unsweetened cocoa powder (not Dutch processed)","1/4 teaspoon salt, optional","1/3 cup coarsely chopped dark chocolate (2 ounces)","1/3 cup coarsely chopped milk chocolate (2 ounces)","2/3 cup chopped pecans, optional"],"assetID":"7a876350-8f48-42e4-b272-ba632f359baf","assetType":"recipe"}}

{"query":"
query GET_SHOPPING_LIST_BY_CATEGORY_AND_ASSET_AND_NORMALLY($recipeImageSize: Int = 240) {
  shoppingList {
    count
    items {
      id
      text
      checked
    }

    byCategory(checked: grouped) {
      categories {
        category
        items {

  id
  text
  checked
  measure

        }
      }
      uncategorized {

  id
  text
  checked
  measure

      }
      checked {

  id
  text
  checked
  measure

      }
    }


  byAsset {
    assets {
      asset {
        id
        title
        url
        primaryImage {
          url(transform: {
            width: $recipeImageSize
          })
        }
      }
      items {

  id
  text
  checked
  measure

      }
    }
    other {

  id
  text
  checked
  measure

    }
  }

  }
}
","variables":{"recipeImageSize":137},"operationName":"GET_SHOPPING_LIST_BY_CATEGORY_AND_ASSET_AND_NORMALLY"}

